1	const PROCESSING_FEE = 5;
2	const FIRST_INSURANCE_RATE = 0.1;
3	const CURSE_SURCHARGE_RATE = 0.5;
4	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
5	const HIGH_ENCHANTMENT_THRESHOLD = 5;
6	const LOYALTY_DISCOUNT_RATE = 0.2;
7	const LOYALTY_YEAR_THRESHOLD = 2;
8	const FOLLOW_UP_DISCOUNT_RATE = 0.15;
9	const DEDUCTIBLE = 100;
10	const CAP_MULTIPLIER = 2;
11	const FRAGILE_ENCHANTMENT_THRESHOLD = 8;
12	const FRAGILE_REIMBURSEMENT_RATE = 0.5;
13	
14	const COMPONENT_BLOCK_SIZE = 3;
15	const COMPONENT_BLOCK_PREMIUM = 60;
16	
17	type ItemTypeInfo = {
18	  basePremium: number;
19	  insuranceValue: number;
20	  isComponent: boolean;
21	};
22	
23	const ITEM_REGISTRY: Record<string, ItemTypeInfo> = {
24	  sword: { basePremium: 100, insuranceValue: 1000, isComponent: false },
25	  amulet: { basePremium: 60, insuranceValue: 600, isComponent: false },
26	  staff: { basePremium: 80, insuranceValue: 800, isComponent: false },
27	  potion: { basePremium: 40, insuranceValue: 400, isComponent: false },
28	  rune: { basePremium: 25, insuranceValue: 250, isComponent: true },
29	  moonstone: { basePremium: 25, insuranceValue: 250, isComponent: true },
30	};
31	
32	const itemInfo = (type: string): ItemTypeInfo => {
33	  const info = ITEM_REGISTRY[type];
34	  if (info === undefined) {
35	    throw new Error(`Unknown item type: ${type}`);
36	  }
37	  return info;
38	};
39	
40	const basePremiumFor = (type: string): number => itemInfo(type).basePremium;
41	
42	const insuranceValueFor = (type: string): number => itemInfo(type).insuranceValue;
43	
44	type Item = {
45	  type: string;
46	  cursed?: boolean;
47	  enchantment?: number;
48	  material?: string;
49	};
50	type QuoteStep = { op: "quote"; items: Item[] };
51	type Damage = { itemType: string; amount: number };
52	type Incident = { cause: string; damages: Damage[] };
53	type ClaimStep = { op: "claim"; policy: number; incident: Incident };
54	type Step = QuoteStep | ClaimStep;
55	type Customer = { yearsWithMHPCO: number };
56	type Scenario = { customer: Customer; steps: Step[] };
57	
58	type Policy = { items: Item[]; remainingCap: number };
59	
60	// Rounding favours MHPCO: premiums round up (customer pays more),
61	// payouts round down (MHPCO pays less).
62	const roundPremiumInMHPCOsFavor = Math.ceil;
63	const roundPayoutInMHPCOsFavor = Math.floor;
64	
65	const groupedBasePremium = (type: string, count: number): number => {
66	  const info = itemInfo(type);
67	  if (info.isComponent && count === COMPONENT_BLOCK_SIZE) {
68	    return COMPONENT_BLOCK_PREMIUM;
69	  }
70	  return count * info.basePremium;
71	};
72	
73	const countByType = (items: Item[]): Map<string, number> => {
74	  const counts = new Map<string, number>();
75	  for (const item of items) {
76	    counts.set(item.type, (counts.get(item.type) ?? 0) + 1);
77	  }
78	  return counts;
79	};
80	
81	const sumBasePremiums = (items: Item[]): number =>
82	  Array.from(countByType(items)).reduce(
83	    (total, [type, count]) => total + groupedBasePremium(type, count),
84	    0,
85	  );
86	
87	const surchargeFor = (item: Item, applies: boolean, rate: number): number =>
88	  applies ? basePremiumFor(item.type) * rate : 0;
89	
90	const isCursed = (item: Item): boolean => item.cursed === true;
91	
92	const isHighlyEnchanted = (item: Item): boolean =>
93	  (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD;
94	
95	const itemSurchargeFor = (item: Item): number =>
96	  surchargeFor(item, isCursed(item), CURSE_SURCHARGE_RATE) +
97	  surchargeFor(item, isHighlyEnchanted(item), HIGH_ENCHANTMENT_SURCHARGE_RATE);
98	
99	const sumItemSurcharges = (items: Item[]): number =>
100	  items.reduce((sum, item) => sum + itemSurchargeFor(item), 0);
101	
102	const firstInsuranceSurcharge = (basePremium: number): number =>
103	  basePremium * FIRST_INSURANCE_RATE;
104	
105	const loyaltyDiscount = (basePremium: number, customer: Customer): number =>
106	  customer.yearsWithMHPCO >= LOYALTY_YEAR_THRESHOLD
107	    ? basePremium * LOYALTY_DISCOUNT_RATE
108	    : 0;
109	
110	const followUpDiscount = (basePremium: number, isFollowUp: boolean): number =>
111	  isFollowUp ? basePremium * FOLLOW_UP_DISCOUNT_RATE : 0;
112	
113	const quotePremium = (
114	  items: Item[],
115	  customer: Customer,
116	  isFollowUp: boolean,
117	): number => {
118	  const basePremium = sumBasePremiums(items);
119	  const insurancePremium = roundPremiumInMHPCOsFavor(
120	    basePremium +
121	      sumItemSurcharges(items) +
122	      firstInsuranceSurcharge(basePremium) -
123	      loyaltyDiscount(basePremium, customer) -
124	      followUpDiscount(basePremium, isFollowUp),
125	  );
126	  return insurancePremium + PROCESSING_FEE;
127	};
128	
129	const insuranceSum = (items: Item[]): number =>
130	  items.reduce((sum, item) => sum + insuranceValueFor(item.type), 0);
131	
132	const isFragile = (item: Item): boolean =>
133	  (item.enchantment ?? 0) >= FRAGILE_ENCHANTMENT_THRESHOLD;
134	
135	const reimbursementRate = (item: Item): number =>
136	  isFragile(item) ? FRAGILE_REIMBURSEMENT_RATE : 1;
137	
138	const findInsuredItem = (items: Item[], itemType: string): Item => {
139	  const insuredItem = items.find((item) => item.type === itemType);
140	  if (insuredItem === undefined) {
141	    throw new Error(`Item not insured by policy: ${itemType}`);
142	  }
143	  return insuredItem;
144	};
145	
146	const damagePayout = (damage: Damage, items: Item[]): number => {
147	  if (damage.amount < 0) {
148	    throw new Error(`Negative damage amount: ${damage.amount}`);
149	  }
150	  const item = findInsuredItem(items, damage.itemType);
151	  return damage.amount * reimbursementRate(item) - DEDUCTIBLE;
152	};
153	
154	const runQuote = (
155	  step: QuoteStep,
156	  customer: Customer,
157	  isFollowUp: boolean,
158	): { result: { premium: number }; policy: Policy } => {
159	  const premium = quotePremium(step.items, customer, isFollowUp);
160	  const policy: Policy = {
161	    items: step.items,
162	    remainingCap: insuranceSum(step.items) * CAP_MULTIPLIER,
163	  };
164	  return { result: { premium }, policy };
165	};
166	
167	const sumDamagePayouts = (damages: Damage[], items: Item[]): number =>
168	  damages.reduce((sum, damage) => sum + damagePayout(damage, items), 0);
169	
170	const assertDamagesWithinInsured = (
171	  damages: Damage[],
172	  items: Item[],
173	): void => {
174	  const insuredCounts = countByType(items);
175	  const damageCounts = new Map<string, number>();
176	  for (const damage of damages) {
177	    damageCounts.set(
178	      damage.itemType,
179	      (damageCounts.get(damage.itemType) ?? 0) + 1,
180	    );
181	  }
182	  for (const [type, count] of damageCounts) {
183	    const insured = insuredCounts.get(type) ?? 0;
184	    if (insured === 0) {
185	      throw new Error(`Item not insured by policy: ${type}`);
186	    }
187	    if (count > insured) {
188	      throw new Error(`More damages than insured items for type: ${type}`);
189	    }
190	  }
191	};
192	
193	const runClaim = (
194	  step: ClaimStep,
195	  policies: Policy[],
196	): { result: { payout: number; remainingCap: number }; policy: Policy } => {
197	  const policy = policies[step.policy];
198	  assertDamagesWithinInsured(step.incident.damages, policy.items);
199	  const rawPayout = sumDamagePayouts(step.incident.damages, policy.items);
200	  const payout = Math.min(roundPayoutInMHPCOsFavor(rawPayout), policy.remainingCap);
201	  const remainingCap = policy.remainingCap - payout;
202	  return {
203	    result: { payout, remainingCap },
204	    policy: { ...policy, remainingCap },
205	  };
206	};
207	
208	export const runScenario = (scenario: Scenario): unknown => {
209	  const policies: Policy[] = [];
210	  const results = scenario.steps.map((step, index) => {
211	    if (step.op === "quote") {
212	      const isFollowUp = index > 0;
213	      const { result, policy } = runQuote(step, scenario.customer, isFollowUp);
214	      policies.push(policy);
215	      return result;
216	    }
217	    const { result, policy } = runClaim(step, policies);
218	    policies[step.policy] = policy;
219	    return result;
220	  });
221	  return { results };
222	};
